// src/lib/store.test.ts
import { describe, it, expect, vi } from 'vitest'
import { createLocalStore } from './store'

describe('createLocalStore', () => {
  it('merges stored partial data over the fallback', () => {})
  it('falls back to default when localStorage.getItem throws (private-mode / disabled storage)', () => {
    const spy = vi.spyOn(Storage.prototype, 'getItem').mockImplementation(() => { throw new Error('blocked') })
    const s = createLocalStore('k', { a: 1 })
    expect(s.get()).toEqual({ a: 1 })
    spy.mockRestore()
  })
  it('falls back to default on corrupted JSON in localStorage', () => {
    localStorage.setItem('k', '{not json')
    // ...
  })
  it('set() survives localStorage.setItem throwing (quota exceeded) and keeps in-memory state', () => {
    const spy = vi.spyOn(Storage.prototype, 'setItem').mockImplementation(() => { throw new Error('quota') })
    // s.set(...) should not throw, and s.get() should reflect the new in-memory value
    spy.mockRestore()
  })
  it('set() accepts both a plain value and an updater function', () => {})
  it('unsubscribe stops further notifications', () => {})
})
